import{_ as t,o,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"75. Reimbursement Of Professional Development Leave","description":"","frontmatter":{"title":"75. Reimbursement Of Professional Development Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["education-pd","leave","allowances","travel"]},"headers":[],"relativePath":"ebas/mspp/leave/75-reimbursement-of-professional-development-leave.md","filePath":"ebas/mspp/leave/75-reimbursement-of-professional-development-leave.md"}'),n={name:"ebas/mspp/leave/75-reimbursement-of-professional-development-leave.md"};function r(i,e,p,l,m,d){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_75-reimbursement-of-professional-development-leave" tabindex="-1">75. Reimbursement Of Professional Development Leave <a class="header-anchor" href="#_75-reimbursement-of-professional-development-leave" aria-label="Permalink to &quot;75. Reimbursement Of Professional Development Leave&quot;">​</a></h1><p>expenses</p><p><strong>a.</strong> An Employee will be entitled to the reimbursement of reasonable expenses incurred in the course of their approved Professional Development Leave, such as:</p><p><strong>(i)</strong> Registration fees, reasonable travel, accommodation and per diem expenses; and/or</p><p><strong>(ii)</strong> Where reasonable, additional childcare expenses where the Employee is the primary care giver of a child or children and has responsibility for the child(ren) during the professional development activity.</p><p><strong>b.</strong> When determining whether an expense is a ‘reasonable expense’ as described at 72(a) above, the Employer will consider amounts set by the Australian Taxation Office (ATO) as adjusted from time to time.</p><p><strong>c.</strong> Applications must be made within 14 days of returning from Professional Development Leave and include official receipts identifying the expense incurred.</p><p><strong>d.</strong> Reimbursement may be claimed using the claim form pro forma set out in</p><p><strong>e.</strong> The Employer must, within 14 days’ of the application for reimbursement notify the Employee of the outcome of the application. In the event that all or part of the application is not approved, the Employer will provide reasons to the Employee in writing.</p><p><strong>f.</strong> Any dispute about the reasonableness of expenses and/or failure of the Employer to approve an application for reimbursement of professional development expenses shall be dealt with under <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">Clause 11</a> – Dispute Settling Procedure.</p><p>Plain language terms: PD leave, training leave.</p>',11)])])}const h=t(n,[["render",r]]);export{c as __pageData,h as default};
